import appInsights from 'applicationinsights';

import { logger } from '../../utils/logger';

/**
 * Types for session binding metrics
 */
export interface MismatchReason {
  ip?: boolean;
  userAgent?: boolean;
  deviceFingerprint?: boolean;
}

export interface BindingMetricEvent {
  userId: string;
  success: boolean;
  mismatches?: MismatchReason;
  path: string;
  enforced: boolean;
  timestamp: Date;
}

/**
 * SessionBindingMetricsService
 *
 * Collects and aggregates session binding validation metrics.
 * Tracks mismatch rates, reasons, and user impact for decision-making.
 *
 * Design principles:
 * - Fast (~1ms per event, no blocking I/O)
 * - Fail-soft (never throws; auth can't fail on metrics error)
 * - Bounded memory (in-memory counters, not arrays)
 * - Observable (posts custom metrics to Application Insights)
 * - Thread-safe (concurrent calls handled safely)
 */
export class SessionBindingMetricsService {
  private static instance: SessionBindingMetricsService;

  // In-memory counters
  private mismatchCount = 0;
  private successCount = 0;
  private mismatchByReason: { ip: number; userAgent: number; deviceFingerprint: number } = {
    ip: 0,
    userAgent: 0,
    deviceFingerprint: 0,
  };
  private lastResetTime = Date.now();
  private rollupInterval = 60000; // 60s rollup window

  private constructor() {
    // Initialize Application Insights if available
    if (appInsights.defaultClient) {
      this.startPeriodicRollup();
    }
  }

  /**
   * Get singleton instance
   */
  static getInstance(): SessionBindingMetricsService {
    if (!SessionBindingMetricsService.instance) {
      SessionBindingMetricsService.instance = new SessionBindingMetricsService();
    }
    return SessionBindingMetricsService.instance;
  }

  /**
   * Record a session binding mismatch event
   * @param event The mismatch event details
   */
  recordMismatch(event: BindingMetricEvent): void {
    try {
      this.mismatchCount++;

      // Track mismatch reasons
      if (event.mismatches) {
        if (event.mismatches.ip) {
          this.mismatchByReason.ip++;
        }
        if (event.mismatches.userAgent) {
          this.mismatchByReason.userAgent++;
        }
        if (event.mismatches.deviceFingerprint) {
          this.mismatchByReason.deviceFingerprint++;
        }
      }

      // Log mismatch for debugging (at warn level per architecture)
      logger.warn('Session binding mismatch recorded', {
        userId: event.userId,
        path: event.path,
        enforced: event.enforced,
        reasons: event.mismatches || {},
        timestamp: event.timestamp.toISOString(),
      });

      // Emit Application Insights custom event (non-blocking)
      this.emitCustomMetric('session_binding_mismatch', event);
    } catch (error) {
      // Fail-soft: never throw from metrics collection
      logger.error('Failed to record session binding mismatch metric', {
        error: error instanceof Error ? error.message : String(error),
      });
    }
  }

  /**
   * Record a session binding success event
   * @param event The success event details (without mismatches)
   */
  recordSuccess(event: Omit<BindingMetricEvent, 'mismatches'>): void {
    try {
      this.successCount++;

      // Emit Application Insights custom event (non-blocking)
      this.emitCustomMetric('session_binding_success', event);
    } catch (error) {
      // Fail-soft: never throw from metrics collection
      logger.error('Failed to record session binding success metric', {
        error: error instanceof Error ? error.message : String(error),
      });
    }
  }

  /**
   * Get current mismatch rate as percentage
   * @returns Percentage (0-100), or 0 if no events recorded
   */
  getMismatchRate(): number {
    const total = this.mismatchCount + this.successCount;
    if (total === 0) {
      return 0; // No events yet
    }
    const rate = (this.mismatchCount / total) * 100;
    return Math.round(rate * 100) / 100; // Round to 2 decimal places
  }

  /**
   * Check if current mismatch rate exceeds alert threshold (5%)
   * @returns True if rate > 5%, false otherwise
   */
  shouldAlertThreshold(): boolean {
    return this.getMismatchRate() > 5;
  }

  /**
   * Get current mismatch counts by reason
   * @returns Object with IP, UserAgent, DeviceFingerprint counts
   */
  getMismatchByReason(): { ip: number; userAgent: number; deviceFingerprint: number } {
    return { ...this.mismatchByReason };
  }

  /**
   * Get total event counts
   * @returns Object with mismatch and success counts
   */
  getEventCounts(): { mismatchCount: number; successCount: number; total: number } {
    return {
      mismatchCount: this.mismatchCount,
      successCount: this.successCount,
      total: this.mismatchCount + this.successCount,
    };
  }

  /**
   * Reset counters (for testing)
   * WARNING: This clears all accumulated metrics. Use with caution.
   */
  reset(): void {
    this.mismatchCount = 0;
    this.successCount = 0;
    this.mismatchByReason = {
      ip: 0,
      userAgent: 0,
      deviceFingerprint: 0,
    };
    this.lastResetTime = Date.now();
  }

  /**
   * Start periodic rollup to Application Insights
   * Posts accumulated metrics every 60 seconds
   * @private
   */
  private startPeriodicRollup(): void {
    // Only run if Application Insights is configured
    if (!process.env.APPINSIGHTS_INSTRUMENTATION_KEY) {
      return;
    }

    setInterval(() => {
      try {
        const rate = this.getMismatchRate();
        const counts = this.getEventCounts();
        const reasons = this.getMismatchByReason();

        // Post aggregated metrics to Application Insights
        if (appInsights.defaultClient && counts.total > 0) {
          appInsights.defaultClient.trackEvent({
            name: 'SessionBindingMetricsRollup',
            properties: {
              mismatchRate: rate.toString(),
              period: 'last_60s',
              threshold: '5%',
              alertTriggered: this.shouldAlertThreshold() ? 'true' : 'false',
            },
            measurements: {
              mismatch_count: counts.mismatchCount,
              success_count: counts.successCount,
              total_count: counts.total,
              mismatch_rate_percent: rate,
              ip_mismatch_count: reasons.ip,
              ua_mismatch_count: reasons.userAgent,
              device_mismatch_count: reasons.deviceFingerprint,
            },
          });
        }
      } catch (error) {
        logger.error('Failed to rollup session binding metrics', {
          error: error instanceof Error ? error.message : String(error),
        });
      }
    }, this.rollupInterval);
  }

  /**
   * Emit a single custom metric event to Application Insights
   * @private
   */
  private emitCustomMetric(
    metricType: 'session_binding_mismatch' | 'session_binding_success',
    event: BindingMetricEvent | Omit<BindingMetricEvent, 'mismatches'>
  ): void {
    try {
      if (!appInsights.defaultClient) {
        return; // Application Insights not configured
      }

      // Post custom event
      appInsights.defaultClient.trackEvent({
        name: 'SessionBindingValidation',
        properties: {
          type: metricType,
          path: event.path,
          enforced: event.enforced.toString(),
          userId: this.hashUserId(event.userId), // Hash for privacy
        },
        measurements: {
          timestamp_unix: event.timestamp.getTime(),
        },
      });
    } catch (error) {
      // Fail-soft: log but don't throw
      logger.debug('Failed to emit custom metric to Application Insights', {
        metricType,
        error: error instanceof Error ? error.message : String(error),
      });
    }
  }

  /**
   * Simple hash of userId for privacy (never emit raw userId)
   * @private
   */
  private hashUserId(userId: string): string {
    if (!userId || userId === 'anonymous') {
      return 'anonymous';
    }
    // Return first 8 chars + hash of rest (not cryptographic, just for obfuscation)
    const hash = userId.split('').reduce((h, c) => (h << 5) - h + c.charCodeAt(0), 0);
    return `${userId.substring(0, 4)}...${Math.abs(hash).toString(16).substring(0, 4)}`;
  }
}

// Export singleton instance
export const sessionBindingMetricsService = SessionBindingMetricsService.getInstance();
